-- ----------------------------
-- Table structure for ich_inheritor
-- ----------------------------
DROP TABLE IF EXISTS `ich_inheritor`;
CREATE TABLE `ich_inheritor`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '传承人姓名',
  `region` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属区县：莲都区、龙泉市、青田县等',
  `intro` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '个人简介',
  `representative_works` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '代表作品描述',
  `story` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '传承故事',
  `avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '头像 URL',
  `create_time` datetime(6) NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1013 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '非遗传承人表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of ich_inheritor
-- ----------------------------
INSERT INTO `ich_inheritor` VALUES (1, ' 徐朝兴', '龙泉市', '龙泉青瓷烧制技艺（首批国家级传承人）\n1943年3月生于浙江龙泉一个普通家庭，自幼在瓷窑烟火中长大，耳濡目染青瓷烧制的全过程，对泥土与火焰的交融产生了浓厚兴趣。由于家境贫寒，13岁时便主动告别学堂，步行80里山路前往龙泉瓷厂拜师学艺，成为当时厂里最年轻的学徒，从此开启了长达66年的青瓷生涯。他凭借吃苦耐劳的性子和对技艺的极致追求，从最基础的揉泥、拉坯做起，一步步成长为青瓷行业的领军人物，1980年被破格提拔为龙泉青瓷研究所所长，先后荣获全国五一劳动奖章、全国优秀科技工作者、亚太地区手工艺大师等多项荣誉，享受国务院政府特殊津贴，用一生坚守诠释了青瓷人的匠心。', '- 《哥窑贯耳瓶》：被故宫博物院收藏，器型规整，开片自然，釉色温润，完美复刻传统哥窑精髓，是当代龙泉青瓷仿古技艺的典范。\n- 《粉青釉跳刀纹梅瓶》：运用独创的“跳刀”技法，瓶身纹理流畅自然，粉青釉色如玉石般细腻，兼具传统韵味与现代审美，曾获全国陶瓷设计评比大奖。\n\n- 《52厘米迎宾大挂盘》：1982年获第二届全国陶瓷设计评比一等奖，被誉为当代“国宝”，收藏于北京中南海紫光阁，是龙泉青瓷走向国家级殿堂的标志性作品。\n\n- 《哥弟混合釉双耳尊》：融合哥窑开片与弟窑釉色的优势，釉色层次丰富，器型端庄大气，被多个国家级博物馆收藏。', '1956年，13岁的徐朝兴正式拜龙泉青瓷老艺人李怀德为师，开启系统性学艺之路。初学阶段，他每天天不亮就起床，反复练习揉泥、拉坯、修坯等基础工序，手上磨出厚厚的老茧也不放弃，仅揉泥一道工序就坚持练习了两年，直到能精准把控泥料的干湿、软硬，为后续技艺提升筑牢根基。1958年，15岁的他凭借扎实的基本功，入选浙江仿古瓷攻关小组，成为小组中最年轻的成员，跟随团队潜心研究古代龙泉青瓷的烧制技艺，复刻经典器型与釉色。在学习过程中，他不仅注重传承古法，更善于摸索创新，反复试验釉料配方、烧制温度和时间，克服了薄胎厚釉烧制易开裂、釉色不均等难题，独创“跳刀”绝技，还相继开发出青瓷玲珑、点缀纹片、露胎装饰等新工艺。此外，他曾借调浙江美术学院担任专业辅导教师，在教学相长中进一步精进技艺，形成了自己独特的艺术风格。', '/pictures/徐朝兴_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (2, '陈爱明', '龙泉市', '龙泉青瓷烧制技艺（第六批国家级传承人）\n1962年生于龙泉青瓷世家，从小在瓷厂周边长大，看着父辈们制作青瓷的过程，逐渐爱上这门古老技艺。1978年，16岁的他正式进入龙泉瓷厂，开启了与青瓷相伴的职业生涯，至今深耕青瓷领域40余年。他性格沉稳，勤于钻研，不仅注重传统技艺的传承，更重视文化素养的提升，1991年主动考入景德镇陶瓷学院美术系深造，系统学习现代陶瓷艺术理论与设计方法，为传统青瓷创作注入现代理念。毕业后，他先后创办仿宋官哥窑瓷厂、龙泉华兴青瓷有限公司，牵头组建龙泉大窑瓷文化研究中心，逐步构建起技艺传承、产品研发、文化推广于一体的发展平台，成为当代龙泉青瓷传承与创新的领军人物，获评中国陶瓷艺术大师、正高级工艺美术师。', '- 《梅子青釉刻花牡丹瓶》：釉色饱满莹润，如青梅般剔透，瓶身刻花细腻流畅，牡丹图案栩栩如生，兼具传统工艺与现代审美，多次在国家级展览中获奖。\n- 《粉青釉象耳瓶》：器型端庄典雅，象耳造型寓意吉祥，粉青釉色温润如玉，开片自然细腻，是传统青瓷技艺与现代造型设计结合的代表作。\n\n- 《青瓷茶具“天青”系列》：主打实用型青瓷，釉色清新淡雅，造型简约大气，适配现代生活场景，既保留了龙泉青瓷的传统韵味，又满足了当代人的使用需求，远销海内外。\n\n- 《春酣国色》：以牡丹为核心元素，釉色层次丰富，刻花工艺精湛，将传统花卉题材与青瓷技艺完美融合，展现了龙泉青瓷的灵动之美。', '1978年进入龙泉瓷厂后，陈爱明从最基础的瓷土陈炼、坯体成型做起，每天泡在车间，反复练习拉坯、修坯、施釉等工序，认真记录每一次烧制的温度、时间与釉色变化，积累了大量实操经验。初学拉坯时，他常常因为力度把控不当，导致坯体坍塌，却从未气馁，每天坚持练习数小时，直到能精准拉制出各种规整的器型。1993年至1994年，他先后拜清华大学美术学院著名陶瓷艺术家高峰、国家级非遗传承人徐朝兴两位青瓷泰斗为师，系统研习手拉坯、跳刀纹等核心技法，全面领悟龙泉窑青瓷的工艺精髓与审美内涵。在学习过程中，他注重“守正创新”，既严格遵循传统烧制工艺，又大胆融合现代设计理念，反复试验釉料调配与装饰手法，在釉色、造型、装饰上形成了自己的风格，成功让传统青瓷兼具艺术性与实用性。此外，他还通过收徒传艺、技艺培训等方式，将自己的所学毫无保留地传授给青年一代，推动青瓷技艺的薪火相传。', '/pictures/陈爱明_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (3, '胡兆雄', '遂昌县', '龙泉青瓷烧制技艺（国家级传承人、丽水首位“大国工匠”）\n1965年生于浙江遂昌，自幼对陶瓷艺术有着浓厚的兴趣，少年时期便经常前往龙泉瓷厂观摩学习，被青瓷的独特魅力深深吸引。1986年，他从湖南轻工业专科学校陶瓷专业毕业，凭借扎实的专业知识，被分配到龙泉上垟国营青瓷厂工作，从此正式投身龙泉青瓷行业，至今从业38载。他从基层技术岗位做起，凭借过硬的技艺和不懈的努力，先后担任技术科长、技术副厂长，1996年创办龙泉市天工青瓷厂，逐步成长为行业内的技术骨干。他始终坚守匠心，深耕细作，成功复烧梅子青、粉青等名贵釉色，推动龙泉青瓷工艺的标准化发展，获评“中国收藏家喜爱的陶瓷艺术大师”“浙江省首席技师”，成为丽水首位“大国工匠”，现任龙泉青瓷研究所所长，致力于青瓷技艺的传承与人才培养。', '- 《粉青釉弦纹瓶》：器型简洁大方，瓶身弦纹规整流畅，粉青釉色温润细腻，无明显开片，尽显龙泉青瓷的素雅之美，被多个收藏家收藏。\n- 《梅子青釉斗笠碗》：造型简约灵动，釉色如青梅般莹润剔透，胎体轻薄，手感细腻，既保留了传统斗笠碗的造型精髓，又融入了现代审美，兼具实用性与艺术性。\n\n- 《G20双耳瓶》：为G20杭州峰会定制作品，器型端庄大气，釉色饱满纯正，双耳造型寓意吉祥，展现了龙泉青瓷的高端工艺水准，成为中外文化交流的重要载体。\n\n- 《青瓷“龙纹”系列摆件》：以龙纹为核心装饰元素，刻花细腻，龙纹栩栩如生，釉色温润，将传统图腾与青瓷技艺完美融合，极具收藏价值。', '胡兆雄的学艺之路始于专业院校的系统学习，在湖南轻工业专科学校期间，他系统学习了陶瓷原料、成型工艺、烧制技术等专业知识，为后续从事青瓷创作奠定了坚实的理论基础。毕业后进入龙泉上垟国营青瓷厂，他没有局限于书本知识，而是主动扎根生产一线，拜厂里的老艺人为师，从最基础的坯体成型、釉料调配做起，反复练习实操技艺，熟悉瓷土的特性和烧制的规律。在学习过程中，他重点钻研传统龙泉青瓷的釉色烧制技艺，针对梅子青、粉青等名贵釉色的复烧难题，反复试验釉料配方和烧制温度，记录每一次试验数据，耗时数年终于成功复烧出质感纯正的梅子青、粉青釉色，还原了传统龙泉青瓷的经典韵味。此外，他还注重技艺的创新与推广，牵头组建高技能人才创新工作室，带领团队攻克工艺难题，同时积极带徒授艺，培养了大批青年青瓷人才，推动龙泉青瓷技艺的传承与发展。', '/pictures/胡兆雄_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (5, '蓝延蓝', '景宁畲族自治县', '景宁畲族非遗（畲族彩带编织技艺，第六批国家级）\n出生于景宁东弄村一个畲族家庭，东弄村是环敕木山十大畲寨里的“文寨”，有着“以技传家”的传统，畲族彩带编织是村里代代相传的技艺。她自幼生长在这样的文化环境中，6岁起便跟随外婆和母亲学习畲族彩带编织，看着长辈们用彩线编织出精美的彩带，作为背带、束带或定情信物，在耳濡目染中爱上了这门指尖技艺。她一生坚守彩带编织，从年少时的模仿学习，到成年后的创新发展，始终深耕方寸织机间，将畲族的文化与祝福融入每一根彩线。2008年，她在村里成立畲族彩带工作室，免费传授编织技艺，至今已有超过2万人次跟随她学习或体验，她编织的彩带还远销海外，从生活用品蜕变为民族艺术品，成为畲族文化的动人表征，2023年入选第六批国家级非遗传承人。', '- 《56个民族名称彩带》：被誉为“彩带王”，长4米，将56个民族的名称与畲族传统花纹结合，编织精细，色彩鲜艳，既展现了畲族彩带的编织技艺，又体现了各民族一家亲的理念，极具文化价值。\n- 《畲族图腾纹彩带》：以畲族凤凰、龙等图腾为核心元素，编织细腻，纹样生动，色彩搭配贴合畲族文化特色，是畲族文化的重要载体，常被作为非遗文创产品推广。\n\n- 《婚庆吉祥纹彩带》：融入畲族婚庆习俗元素，编织出吉祥图案，寓意婚姻美满、幸福安康，既是畲族传统婚庆的必备物品，也是极具特色的民俗工艺品。\n\n- 《彩带情思》系列：将畲族的生活场景、山歌意境融入编织图案，线条流畅，色彩柔和，兼具艺术性与观赏性，多次在非遗展览中展出。', '蓝延蓝的学艺之路始于家庭传承，6岁时便坐在外婆的织机旁，模仿长辈的动作，学习穿线、打结、织布，从最基础的编织手法学起。外婆是村里有名的彩带编织艺人，对她要求严格，每一个编织动作、每一根彩线的搭配，都必须做到精准无误。初学阶段，她经常因为手指被彩线磨破、编织图案出错而气馁，但在长辈的鼓励下，她始终没有放弃，每天坚持练习，慢慢掌握了传统彩带的编织技法，熟悉了畲族传统纹样的寓意和编织方法。随着技艺的提升，她不满足于传统样式，开始大胆创新，尝试将汉字、畲族图腾与传统花纹结合，突破传统彩带的长度和图案限制。为了织出更精美的作品，她反复试验彩线的搭配、编织的密度，耗时数月织就长达4米的“彩带王”，将56个民族的名称编织其中，成为极具纪念意义的作品。此外，她还不断优化编织工具和技法，让彩带编织更高效、更精美，同时通过开设工作室、进校园、进社区等方式，将技艺传授给更多人，让畲族彩带编织技艺代代相传。', '/pictures/蓝延蓝_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (6, '吴式求', '庆元县', '庆元方言（市级传承人）\n1936年生于浙江庆元，成长在庆元乡村，自幼便说着庆元方言长大，对家乡的方言有着深厚的感情。他自幼热爱学习，勤奋刻苦，长大后成为一名教师，在教学过程中，发现庆元方言作为地方文化的重要载体，正在逐渐被年轻一代遗忘，许多古老的方言词汇、谚语、童谣面临失传的风险。出于对家乡文化的热爱和保护意识，他从青年时期开始，便利用课余时间，深入庆元各个乡镇，走访老人，记录庆元方言的词汇、发音、语法，开启了长达数十年的庆元方言研究与抢救工作。他自学语言学、文字学知识，克服没有专业资料、发音难以记录等困难，潜心研究庆元方言的历史渊源和演变规律，成为庆元方言研究的权威人士，被评为庆元方言市级非遗传承人。', '吴式求的方言传承与研究之路，没有固定的师傅，全靠自己的摸索和坚守。青年时期，他开始有意识地收集庆元方言词汇，每天利用课余时间，走访庆元各个乡镇的老人，耐心倾听他们的方言表达，用笔记本记录下每一个方言词汇、谚语、童谣，同时学习国际音标，尝试用国际音标注音，解决方言发音难以记录的难题。为了准确掌握庆元方言的语法和发音规律，他反复对比不同乡镇的方言差异，查阅大量语言学、文字学资料，自学方言研究的专业方法，不断完善庆元方言的记录体系。他还深入研究庆元方言与古代汉语的联系，挖掘方言中的古音字源，抢救性记录濒临失传的方言童谣、谚语和民间故事。数十年间，他累计走访老人数百人，记录方言资料数十万字，克服了资金短缺、身体不便等困难，始终坚守在方言保护与传承的一线，最终完成《庆元方言研究》等专著，为庆元方言的抢救、保护与传承作出了重要贡献。', '- 《庆元方言研究》：庆元方言研究的权威专著，系统梳理了庆元方言的历史渊源、发音规律、词汇特点、语法结构，收录了大量庆元方言词汇、谚语、童谣，是庆元方言保护与传承的重要文献。\n- 《庆元方言古音字源初探》：深入挖掘庆元方言中的古音字，分析其与古代汉语的联系，为研究庆元方言的历史演变提供了重要依据，填补了庆元方言古音字研究的空白。\n\n- 《古老珍贵的庆元方言》：科普性读物，用通俗易懂的语言介绍庆元方言的特点、价值和传承现状，收录了大量生动的方言案例，适合大众阅读，助力庆元方言的普及与传播。\n\n- 庆元方言音像资料：录制了大量庆元方言的发音、童谣、谚语音频，抢救性保存了庆元方言的原始发音，为后续方言研究和传承提供了珍贵的视听资料。', '/pictures/吴式求_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (7, '兰金美', '莲都区', '（畲族服饰制作技艺・省级传承人）\n1978 年 3 月生，浙江丽水莲都人，畲族丽水市政府。\n自幼受畲族服饰文化熏陶，对畲绣、彩带、凤凰装等传统技艺耳濡目染。\n2009 年创立 “畲凤” 品牌，专注畲族服饰的抢救、复原与创新丽水市政府。\n2021 年在古堰画乡开设畲凤非遗工坊，打造集培训、展示、文创于一体的传承平台丽水市政府。\n坚持 “非遗 + 时尚 + 生活” 理念，推动畲族服饰从传统走向现代、走向国际。\n现任全国妇联执委、浙江省政协常委，获全国民族团结进步模范个人等荣誉丽水市政府。', '凤舞九天・涅槃新生系列华服：融合畲族婚俗、彩带、畲绣等十项非遗技艺，2025 年亮相意大利米兰时装周。\n仙都黄帝祭祀大典礼仪服饰：将千年礼仪与畲族审美融入设计，成为文化展示标杆。\n畲族凤凰装改良系列：保留传统形制，适配现代日常穿着，带动畲族妇女就业增收。', '她从小跟着长辈学刺绣、织彩带，耳濡目染爱上畲族服饰。成年后，她发现很多传统纹样、技艺正在慢慢消失，便下定决心系统整理、抢救老技艺。她走访畲族村寨，向老一辈手艺人请教，把濒临失传的针法、版型、纹样一一记录复原，再融入现代设计，让老手艺 “活” 在当下。', '/pictures/兰金美_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (8, '张启天', '云和县', '云和板龙舞（传统民俗）\n75岁，云和县凤凰山街道巧云村人，云和板龙舞第四代非遗传承人，被誉为云和板龙制作的“扛把子”。从事板龙制作40余年，精通板龙扎制、编糊、彩绘全流程技艺，是目前云和少数能独立完成板龙龙头制作的手艺人，用匠心守护着拥有700年历史的板龙文化，多次带领团队打造大型板龙展演，助力云和非遗走向更广阔的舞台。', '- 2005年“处州第一龙”：全长208节、连绵400米，在丽水国际摄影文化节龙狮大会中脱颖而出，斩获荣誉。\n- 巧云祥龙：108节龙身，长度达200米，亮相云和元宵节展演，再现“万人空巷看龙灯”的盛景，被央视报道。\n\n- 迷你版教学板龙：适配校园教学与文化展示，用于普及板龙制作技艺，走进云和县实验幼儿园、巧云村文化礼堂。', '云和板龙舞最早可追溯至元末明初，是当地人祈求风调雨顺、寄托乡愁的重要民俗，但随着老艺人离世，板龙制作技艺一度面临传承困境。张启天深知，板龙不仅是一件道具，更是云和人的文化情结，他暗下决心要守住这门老手艺。为了保证技艺的原汁原味，他坚持手工制作，挑选韧性极佳的毛竹，每一根竹篾都要反复打磨，每一笔彩绘都要提前调试色彩，哪怕制作一条完整的板龙需要150天，也从不懈怠。\n有一次，为了赶制元宵节展演的200米长板龙，他带领团队从年初二就开始日夜赶工，每天工作超过12小时，手上的老茧磨平了又增厚，划伤的口子好了又复发，却从没有抱怨过。有人劝他“简化工序、用机器替代”，他却说：“板龙的魂在手工里，偷工减料就是丢了老祖宗的东西。” 除了坚守制作技艺，他还主动改良板龙，用LED灯替代明火，既消除安全隐患，又让龙灯在夜晚更加绚丽；同时，他免费收徒传艺，为幼儿园制作迷你板龙用于教学，让孩子们从小接触板龙文化，用一生践行“让板龙技艺代代相传”的承诺。', '/pictures/张启天_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (10, '张爱廷', '青田县', '（青田石雕，第二批国家级传承人）\n1936年生于浙江青田山口镇，自幼喜爱绘画与雕刻，13岁时拜青田石雕老艺人朱正普为师，正式开启石雕学艺之路，至今深耕青田石雕领域60余年。他性格坚韧，勤于钻研，不仅精通传统石雕技艺，还注重文化素养的提升，自学绘画、书法，将书画艺术融入石雕创作，形成了独特的艺术风格。他先后在青田石雕厂、青田石雕研究所工作，曾任青田石雕行业协会会长，推动青田石雕的标准化、产业化发展，获评中国工艺美术大师、国家级非遗传承人，享受国务院政府特殊津贴，其作品多次在国家级展览中获奖，被多个博物馆收藏。', '- 《百鸟朝凤》：采用青田冻石雕刻，构图恢弘，凤凰造型端庄华贵，百鸟姿态各异，雕刻精细，色彩搭配自然，展现了青田石雕的精湛技艺，被中国工艺美术馆收藏。\n- 《十八罗汉》：一套十八件作品，每尊罗汉神态各异，栩栩如生，衣纹流畅自然，细节刻画精湛，兼具传统佛教文化内涵与艺术价值，是青田石雕人物雕刻的巅峰之作。\n\n- 《春满人间》：以山水、花鸟为核心元素，融入国画构图技巧，画面层次丰富，春意盎然，将自然之美与雕刻技艺完美融合，体现了作者的艺术审美。\n\n- 《蔬果篮》：采用写实手法，雕刻各种蔬果，造型逼真，质感细腻，仿佛伸手可及，展现了青田石雕“以假乱真”的技艺水准，成为民间工艺的经典之作。', '13岁拜师后，张爱廷从选料、打坯、修光等基础工序学起，每天泡在工作室，反复练习雕刻技法，认真观察师傅的操作细节，记录每一个雕刻步骤的技巧。初学阶段，他重点学习花鸟、人物的雕刻，尤其是人物的神态刻画，经常对着镜子模仿人物表情，反复打磨作品的面部细节，力求形神兼备。青年时期，他拜林如奎为师，进一步精进技艺，学习“因材施艺”的创作理念，同时借鉴国画的构图技巧，让石雕作品更具画面感。他还大胆创新，尝试将现代题材融入传统石雕，突破传统花鸟、山水题材的局限，创作了大量反映时代风貌的作品。为了提升技艺，他多次前往北京、上海等地交流学习，吸收其他雕刻门类的精华，优化雕刻工具与技法，让作品的精细度和艺术性大幅提升。此外，他积极带徒授艺，培养了大批青年石雕人才，推动青田石雕技艺的薪火相传。', '/pictures/张爱廷_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (11, '吴陈俊', '松阳县', '高腔（松阳高腔）\n吴陈俊（1933.08-2015.02），汉族，松阳县人，第三批国家级非物质文化遗产项目松阳高腔代表性传承人，被誉为松阳高腔“花旦标杆”。深耕松阳高腔数十年，主攻花旦行当，技艺精湛、唱腔地道，不仅是舞台上的核心演员，更是松阳高腔技艺的重要传承者，牵头开展技艺传承与剧目抢救，为这一“戏曲界活化石”的延续奠定了坚实基础。', '- 经典剧目：《芦花记》《葵花记》《夫人戏》《白兔记》《拜刀记》《判乌盆》《扫窗会》等，擅长花旦角色演绎，唱腔与表演成为松阳高腔的标杆。\n- 抢救性录音作品：1957年、1959年参与松阳高腔抢救性录音，留存了多个经典唱段，为技艺传承提供了原始依据。\n\n- 传承成果：培养数十名松阳高腔演员，其中子女吴永明等人成为市级传承人，延续家族传承脉络，让松阳高腔得以活态延续。', '松阳高腔是浙江省现存最古老的剧种之一，已有600多年历史，被誉为“南戏活化石”，但在时代发展中，面临剧目流失、艺人老化、传承断层的困境。吴陈俊深知这门技艺的珍贵，从年轻时就埋下了“守护与传承”的种子，不仅坚守舞台演出，更主动扛起传艺责任。\n1978年，他开始重点培养传承人，首先将自己的子女吴关永、吴永清、吴永明、吴关妹纳入门下，手把手传授唱腔与表演技艺，让高腔技艺在家族中延续。次年，他又主动招收叶祖区、李王英、洪永娇、华剑英等青年演员，毫无保留地分享自己的技艺与舞台经验，耐心纠正每一个动作与唱腔，生怕遗漏任何一个细节。有人问他，为何要如此费心传艺，他说：“松阳高腔是老祖宗留下的宝贝，我不能让它在我这一代断了根。”\n\n即便到了晚年，他依旧坚守传承一线，哪怕身体不便，也会坐在戏班排练场，指导年轻演员打磨技艺，回忆整理失传的唱词与剧目。他用一生的坚守，让松阳高腔的技艺得以延续，为后续的传承发展留下了宝贵的“活资料”，而他的子女也成为松阳高腔传承的中坚力量，延续着他的传承初心。', '/pictures/吴陈俊_1.webp', '2025-12-01 00:00:00.000000');
INSERT INTO `ich_inheritor` VALUES (12, '刘夏英', '缙云县', '剪纸（缙云剪纸）\n刘夏英，缙云县剪纸市级传承人，从事剪纸技艺五十余年，深耕缙云剪纸的传承、创新与推广，被誉为“缙云剪纸出海第一人”。她精通单色、七彩立体剪纸技艺，坚守传统剪纸的阴阳结合、精致工整的特色，同时融入现代设计理念，让缙云剪纸走出国门、走向世界，自费创办剪纸博物馆，用一把剪刀传承中华美学与缙云文化。', '- 《黄帝缙云·人间仙都》：七层彩纸叠剪而成，兼具水墨意境与三维立体质感，亮相法国巴黎龙舟嘉年华非遗市集，展现黄帝文化与中华美学。\n- 《德被八方驭龙升天》：以黄帝文化为题材，色彩绚丽、工艺精湛，走进巴黎孔子学院，获得海外观众广泛赞誉。\n\n- 《仙都系列》《缙云烧饼系列》：题材源自缙云本土山水与民俗，充满乡土气息，多次在国家级、省级比赛中获奖，同时开发为文创产品，走进日常生活。\n\n2. 金理慧（缙云竹编·区级传承人）', '“传统不是枷锁，是创新的跳板。”这是刘夏英坚守传承五十余年的初心。在传承过程中，她发现缙云剪纸虽有独特魅力，但面临受众老龄化、传播渠道单一的困境，很多年轻人对这门老手艺了解甚少。为了让剪纸技艺活起来、传下去，她不仅坚守古法技艺，更主动拥抱创新，走出了一条“传承+创新+出海”的传承之路。\n2015年，她自费创办缙云县剪纸博物馆，为剪纸技艺的传承搭建起展示、交流与教学的平台，免费向公众开放，让更多人了解缙云剪纸的文化内涵。为了吸引年轻群体，她将现代设计融入剪纸，开发出五大类上万个花色品种的文创产品，还巧妙借势热门电影，教留学生剪动漫形象，用“非遗+电影”的跨界形式让传统艺术“出圈”。她还尝试直播教学，吸引了大量网友关注，让缙云剪纸通过网络走向更广阔的舞台。\n\n更让人动容的是，她带着自己的剪纸作品走出国门，先后亮相法国巴黎龙舟嘉年华非遗市集、巴黎孔子学院，让缙云剪纸成为中外文化交流的桥梁，作品已走进法国、瑞士、意大利等多个国家。有人问她为何如此执着，她说：“我要通过自己的剪刀，剪出缙云的故事、中国文化的故事，让老手艺在新时代焕发新生。” 五十余年坚守，她用一把剪刀，守住了剪纸的匠心，也剪出了非遗传承的新可能。', '/pictures/刘夏英_1.webp', '2025-12-01 00:00:00.000000');

SET FOREIGN_KEY_CHECKS = 1;
